import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { SegmentCustomEvent } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { ClientTransactionsService } from "src/app/core/services/client-transactions.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import * as customValidators from "src/app/core/validators/custom-validators";
import { AccessRight } from "src/app/views/Models/Permissions/AccessRight";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { Bank } from "src/app/views/Models/Settings/BranchReference";
import { LoanApplicationsService } from "src/app/core/services/loan-applications.service";
import { ClientLoanApplicationResponse } from "src/app/views/Models/Client/ApplicationClient";
import { pagingService } from "src/app/core/services/paging.service";
import { sortingService } from "src/app/core/services/sorting.service";
import { ITransType } from "src/app/views/Models/References/TransactionsType";
import { ApplicationTrasnactionResponse } from "src/app/views/Models/ClientTransactions/ClientTransaction";
import { formatNumber } from "@angular/common";
import { format } from "date-fns";
import { InputMaskingService } from "src/app/core/services/input-masking.service";

interface ClientSearchSection {
  visible: boolean;
  clientInformation: SearchResult;
}
interface segmentInformation {
  name: string;
  pageAction: number;
  windowCode: string;
  hasPermission: boolean;
}
interface SegmentSection {
  visible: boolean;
  allAvaliableSegments: segmentInformation[];
  selectedSegment: segmentInformation;
  disable: boolean;
}
interface ApplicationTransactionSection {
  visible: boolean;
  formGroup: FormGroup;
  checkIfInputsValid: boolean;
}
interface ClientLoanApplicationSection {
  visible: boolean;
  clientApplication: ClientLoanApplicationResponse[];
}
interface LoanApplicationTransactionGrid {
  visible: boolean;
  transactions: ApplicationTrasnactionResponse[];
}
interface DatabaseResponses {
  bankType: StaticRef[];
  banks: Bank[];
  accessRight: AccessRight[];
  transactionTypes: ITransType[];
}
@Component({
  selector: "app-application-financial-transaction",
  templateUrl: "./application-financial-transaction.page.html",
  styleUrls: ["./application-financial-transaction.page.scss"],
})
export class ApplicationFinancialTransactionPage implements OnInit {
  //#region Variables
  showLoader: boolean = false;
  segmentSection: SegmentSection;
  clientSearchCardSection: ClientSearchSection;
  applicationTransactionSection: ApplicationTransactionSection;
  databaseResponses: DatabaseResponses;
  clientLoanApplicationSection: ClientLoanApplicationSection;
  loanApplicationTransactionGrid: LoanApplicationTransactionGrid;
  pagingObject: { page: number };
  sortingObject: { sortingIconClass: string; sortingIconParam: string } = {
    sortingIconClass: null,
    sortingIconParam: null,
  };

  constructor(
    private referencesService: ReferencesService,
    private formBuilder: FormBuilder,
    private authService: MohassilAuthService,
    private clientTransactionsService: ClientTransactionsService,
    private loanApplicationService: LoanApplicationsService,
    public pagingService: pagingService,
    private sortingService: sortingService,
    private alertService: AlertService,
    public inputMaskingService: InputMaskingService
  ) {}

  async ngOnInit() {
    this.showLoader = true;
    this.initializeState();
    this.databaseResponses.bankType =
      await this.referencesService.getBankType();
    this.databaseResponses.accessRight =
      await this.authService.getAccessRights();
    this.databaseResponses.transactionTypes =
      await this.referencesService.getApplicationTransactionTypes();

    this.segmentSection = {
      visible: true,
      allAvaliableSegments: [
        {
          name: "إدخال حركات ماليه لطلبات القروض",
          pageAction: 1,
          windowCode: "5636",
          hasPermission: this.databaseResponses.accessRight.some(
            (x) => x.window_code === "5636"
          ),
        },
        {
          name: "تعديل حركات ماليه لطلبات القروض",
          pageAction: 3,
          windowCode: "5637",
          hasPermission: this.databaseResponses.accessRight.some(
            (x) => x.window_code === "5637"
          ),
        },
        {
          name: "حذف حركات ماليه لطلبات القروض",
          pageAction: 3,
          windowCode: "5638",
          hasPermission: this.databaseResponses.accessRight.some(
            (x) => x.window_code === "5638"
          ),
        },
      ],
      selectedSegment: null,
      disable: false,
    };
    this.segmentSection.selectedSegment =
      this.segmentSection.allAvaliableSegments.find((x) => x.hasPermission);
    this.showLoader = false;
  }
  get allSegmentsThatHavePermission() {
    return this.segmentSection.allAvaliableSegments.filter(
      (x) => x.hasPermission
    );
  }
  async initializeState() {
    this.segmentSection = {
      visible: false,
      allAvaliableSegments: [],
      selectedSegment: null,
      disable: true,
    };
    this.clientSearchCardSection = {
      visible: true,
      clientInformation: null,
    };
    this.applicationTransactionSection = {
      visible: false,
      checkIfInputsValid: false,
      formGroup: this.formBuilder.group({
        clientKey: [null],
        clientName: [null],
        clientCode: [null],
        applicationKey: [null],
        applicationCode: [null],
        decEffectiveDate: [null],
        aprvAm: [null],
        loanUsageName: [null],
        transactionCode: [null],
        transactionType: [
          null,
          customValidators.transactionTypeValidator({
            required: true,
          }),
        ],
        transactionAmount: [
          null,
          [
            customValidators.transactionAmountValidator({
              required: true,
              valueGreaterThanZero: true,
            }),
          ],
        ],
        transactionMaturityDate: [
          null,
          customValidators.dateTypeStringValidator({
            required: true,
          }),
        ],
        bankType: [
          null,
          [customValidators.bankTypeValidator({ required: true })],
        ],
        transactionBank: [
          null,
          [customValidators.bankNameValidator({ required: true })],
        ],
        transactionVoucher: [null],
        uuc: [null],
      }),
    };
    this.pagingObject = {
      page: 1,
    };
    this.clientLoanApplicationSection = {
      visible: false,
      clientApplication: [],
    };
    this.databaseResponses = {
      banks: [],
      bankType: [],
      accessRight: [],
      transactionTypes: [],
    };
    this.loanApplicationTransactionGrid = {
      visible: false,
      transactions: [],
    };
  }
  async clientSelected(searchResult: SearchResult) {
    try {
      this.showLoader = true;
      switch (this.segmentSection.selectedSegment.windowCode) {
        case "5636": {
          await this.insertSegment(searchResult);
          break;
        }
        case "5637": {
          await this.editSegment(searchResult);
          break;
        }
        case "5638": {
          await this.deleteSegment(searchResult);
          break;
        }
      }
    } catch (error) {
      this.alertService.showAlertError(error.error, false);
    } finally {
      this.showLoader = false;
    }
  }
  transactionSegmentChanging(event: any): void {
    const segmentEvent = event as SegmentCustomEvent;
    this.setSelectedTransactionSegment(segmentEvent.detail.value);
    this.resetClientSearchComponent();
  }
  setSelectedTransactionSegment(windowCode: string) {
    this.segmentSection.selectedSegment =
      this.segmentSection.allAvaliableSegments.find(
        (x) => x.windowCode === windowCode
      );
  }
  resetClientSearchComponent() {
    this.clientSearchCardSection.visible = false;
    this.clientLoanApplicationSection.visible = false;
    this.applicationTransactionSection.visible = false;
    this.loanApplicationTransactionGrid.visible = false;
    setTimeout(() => (this.clientSearchCardSection.visible = true), 0);
  }
  changePaginationPage = async (newPage: number) => {
    this.pagingObject.page = newPage;
  };
  public sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingObject.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingObject.sortingIconParam = param;
  }
  backButton() {
    if (this.clientLoanApplicationSection.visible) {
      this.clientLoanApplicationSection.visible = false;
      this.clientSearchCardSection.visible = true;
    }
    if (this.loanApplicationTransactionGrid.visible) {
      this.loanApplicationTransactionGrid.visible = false;
      this.clientSearchCardSection.visible = true;
    }
    if (
      this.applicationTransactionSection.visible &&
      this.segmentSection.selectedSegment.windowCode === "5637"
    ) {
      this.applicationTransactionSection.visible = false;
      this.loanApplicationTransactionGrid.visible = true;
      this.applicationTransactionSection.formGroup.reset();
    }
    if (
      this.applicationTransactionSection.visible &&
      this.segmentSection.selectedSegment.windowCode === "5636"
    ) {
      this.applicationTransactionSection.visible = false;
      this.clientLoanApplicationSection.visible = true;
      this.applicationTransactionSection.formGroup.reset();
    }
  }
  applicationSelected(application: ClientLoanApplicationResponse) {
    this.clientLoanApplicationSection.visible = false;
    this.applicationTransactionSection.visible = true;
    this.applicationTransactionSection.formGroup.patchValue({
      clientCode: application.client_code,
      clientName: application.client_name,
      applicationKey: application.application_key,
      applicationCode: application.application_code,
      decEffectiveDate: format(
        new Date(application.dec_effective_date),
        "yyyy-MM-dd"
      ),
      aprvAm: application.aprv_am,
      loanUsageName: application.loan_usage_name,
    });
  }
  async getBanks() {
    this.applicationTransactionSection.formGroup.patchValue({
      bankKey: null,
    });
    this.databaseResponses.banks =
      await this.referencesService.getBanksByBankType(
        Number(this.applicationTransactionSection.formGroup.value.bankType)
      );
  }
  async insertSegment(searchResult: SearchResult) {
    this.clientLoanApplicationSection.clientApplication =
      await this.loanApplicationService.getClientLoanApplications(
        searchResult.client_key.toString()
      );
    this.applicationTransactionSection.formGroup.patchValue({
      clientKey: searchResult.client_key,
      applicationKey: searchResult.application_key,
    });
    this.clientSearchCardSection.visible = false;
    this.clientLoanApplicationSection.visible = true;
  }
  async editSegment(searchResult: SearchResult) {
    this.loanApplicationTransactionGrid.transactions =
      await this.clientTransactionsService.getApplicationTransactions(
        searchResult.client_key.toString()
      );
    this.clientSearchCardSection.visible = false;
    this.loanApplicationTransactionGrid.visible = true;
  }
  async deleteSegment(searchResult: SearchResult) {
    this.loanApplicationTransactionGrid.transactions =
      await this.clientTransactionsService.getApplicationTransactions(
        searchResult.client_key.toString()
      );
    this.clientSearchCardSection.visible = false;
    this.loanApplicationTransactionGrid.visible = true;
  }
  async deleteClientTransaction(transaction: ApplicationTrasnactionResponse) {
    if (!(await this.alertService.SaveAlert())) return;
    try {
      this.showLoader = true;
      await this.clientTransactionsService.deleteClientTransaction(
        Number(transaction.trans_code),
        transaction.uuc.toString()
      );
      this.alertService.showAlertConfirm("لقد تم حذف الحركة ", true);
    } catch (error) {
      this.alertService.showAlertError(error.error, false);
      throw error;
    } finally {
      this.showLoader = false;
    }
  }
  async openEditForm(transactionData: ApplicationTrasnactionResponse) {
    this.showLoader = true;
    let applicationTransaction =
      await this.clientTransactionsService.getApplicationTransactionByTransCode(
        transactionData.trans_code
      );
    this.applicationTransactionSection.formGroup.patchValue({
      clientName: applicationTransaction.client_name,
      clientCode:
        applicationTransaction.org_branch_code +
        "/" +
        applicationTransaction.client_code,
      transactionType: applicationTransaction.type_key,
      transactionCode: Number(applicationTransaction.trans_code),
      transactionAmount: formatNumber(
        Number(applicationTransaction.trans_amount),
        "en-US",
        "1.0-2"
      ),
      transactionMaturityDate: format(
        new Date(applicationTransaction.trans_act_date),
        "yyyy-MM-dd"
      ),
      transactionVoucher: applicationTransaction.trans_vouch,
      bankType: applicationTransaction.bank_type.toString(),
      transactionBank: applicationTransaction.cur_bank_key.toString(),
      uuc: applicationTransaction.uuc.toString(),
    });
    await this.getBanks();
    this.loanApplicationTransactionGrid.visible = false;
    this.applicationTransactionSection.visible = true;
    this.showLoader = false;
  }
  async insertClientTransaction() {
    if (!this.applicationTransactionSection.formGroup.valid)
      return (this.applicationTransactionSection.checkIfInputsValid = true);
    if (!(await this.alertService.SaveAlert())) return;
    try {
      this.showLoader = true;
      console.log(this.applicationTransactionSection.formGroup.value);
      await this.clientTransactionsService.insertLoanApplicationTransaction(
        this.applicationTransactionSection.formGroup.value
      );
      this.alertService.showAlertConfirm("لقد تم الحفظ بنجاح", true);
    } catch (error) {
      this.alertService.showAlertError(error.error, false);
      throw error;
    } finally {
      this.showLoader = false;
    }
  }
  async editClientTransaction() {
    if (!this.applicationTransactionSection.formGroup.valid)
      return (this.applicationTransactionSection.checkIfInputsValid = true);
    if (!(await this.alertService.SaveAlert())) return;
    try {
      this.showLoader = true;
      await this.clientTransactionsService.editClientTransaction({
        transCode:
          this.applicationTransactionSection.formGroup.value.transactionCode,
        transAmount:
          this.applicationTransactionSection.formGroup.value.transactionAmount,
        transActionDate:
          this.applicationTransactionSection.formGroup.value
            .transactionMaturityDate,
        transVouch:
          this.applicationTransactionSection.formGroup.value.transactionVoucher,
        transactionType:
          this.applicationTransactionSection.formGroup.value.transactionType,
        bankKey:
          this.applicationTransactionSection.formGroup.value.transactionBank,
        uuc: this.applicationTransactionSection.formGroup.value.uuc,
      });
      this.alertService.showAlertConfirm("لقد تم الحفظ بنجاح", true);
    } catch (error) {
      this.alertService.showAlertError(error.error, false);
      throw error;
    } finally {
      this.showLoader = false;
    }
  }
}
